const input = $node["你的要点"].json;
const article = $input.first().json.choices[0].message.content;

// 提取前200字作为摘要
const summary = article.replace(/[#*`\\[\\]]/g, '').substring(0, 200).replace(/\\n/g, ' ');
const title = input.topic;
const now = new Date().toISOString();
const dateStr = now.split('T')[0];

const jsonld = {
  "@context": "https://schema.org",
  "@type": "Article",
  "headline": title,
  "description": summary,
  "datePublished": now,
  "author": { "@type": "Person", "name": "zkoner" },
  "publisher": { "@type": "Organization", "name": "zkoner", "url": "https://zkoner.com" }
};

return [{
  title: title,
  article: article,
  summary: summary,
  jsonld: JSON.stringify(jsonld, null, 2),
  keywords: input.keywords.join(', '),
  category: input.category,
  date: dateStr
}];

const seo = $node["生成 SEO + JSON-LD"].json;

// 提取各平台内容
const getContent = function(nodeName) {
  try {
    return $node[nodeName].json.choices[0].message.content;
  } catch(e) {
    return '(等待 AI 响应...)请检查 API Key 配置';
  }
};

const zhihuArticle = getContent('改写成知乎版');
const xhsNote = getContent('改写成小红书版');

return [{
  // 核心文章 (发布到 zkoner.com/blog/)
  master: {
    title: seo.title,
    article: seo.article,
    summary: seo.summary,
    jsonld: seo.jsonld,
    keywords: seo.keywords,
    category: seo.category,
    date: seo.date
  },
  // 知乎版
  zhihu: {
    platform: "知乎",
    content: zhihuArticle,
    action: "手动发布到 zhihu.com"
  },
  // 小红书版
  xiaohongshu: {
    platform: "小红书",
    content: xhsNote,
    action: "手动发布到 xiaohongshu.com"
  },
  // 发布清单
  publishList: [
    { platform: "zkoner.com/blog", action: "✅ 自动", note: "后续可接入git push" },
    { platform: "知乎", action: "✋ 手动", note: "复制内容到知乎发布" },
    { platform: "小红书", action: "✋ 手动", note: "复制内容到小红书发布" }
  ]
}];
